Active FfiConverterTypeActive::lift(RustBuffer buf) {
    auto stream = RustStream(&buf);
    auto ret = FfiConverterTypeActive::read(stream);

    rustbuffer_free(buf);

    return std::move(ret);
}

RustBuffer FfiConverterTypeActive::lower(const Active &val) {
    auto buf = rustbuffer_alloc(allocation_size(val));
    auto stream = RustStream(&buf);

    FfiConverterTypeActive::write(stream, val);

    return std::move(buf);
}

Active FfiConverterTypeActive::read(RustStream &stream) {
    return {
        FfiConverterOptionalString::read(stream),
        FfiConverterString::read(stream),
        FfiConverterOptionalString::read(stream),
        FfiConverterOptionalDouble::read(stream),
        FfiConverterOptionalDouble::read(stream),
        FfiConverterOptionalDouble::read(stream),
        FfiConverterOptionalDouble::read(stream),
        FfiConverterOptionalDouble::read(stream),
        FfiConverterOptionalDouble::read(stream),
        FfiConverterOptionalInt64::read(stream),
        FfiConverterOptionalDouble::read(stream),
        FfiConverterOptionalInt64::read(stream)
    };
}

void FfiConverterTypeActive::write(RustStream &stream, const Active &val) {
    FfiConverterOptionalString::write(stream, val.data_type);
    FfiConverterString::write(stream, val.symbol);
    FfiConverterOptionalString::write(stream, val.name);
    FfiConverterOptionalDouble::write(stream, val.open_price);
    FfiConverterOptionalDouble::write(stream, val.high_price);
    FfiConverterOptionalDouble::write(stream, val.low_price);
    FfiConverterOptionalDouble::write(stream, val.close_price);
    FfiConverterOptionalDouble::write(stream, val.change);
    FfiConverterOptionalDouble::write(stream, val.change_percent);
    FfiConverterOptionalInt64::write(stream, val.trade_volume);
    FfiConverterOptionalDouble::write(stream, val.trade_value);
    FfiConverterOptionalInt64::write(stream, val.last_updated);
}

uint64_t FfiConverterTypeActive::allocation_size(const Active &val) {
    
    return 
        FfiConverterOptionalString::allocation_size(val.data_type) +
        FfiConverterString::allocation_size(val.symbol) +
        FfiConverterOptionalString::allocation_size(val.name) +
        FfiConverterOptionalDouble::allocation_size(val.open_price) +
        FfiConverterOptionalDouble::allocation_size(val.high_price) +
        FfiConverterOptionalDouble::allocation_size(val.low_price) +
        FfiConverterOptionalDouble::allocation_size(val.close_price) +
        FfiConverterOptionalDouble::allocation_size(val.change) +
        FfiConverterOptionalDouble::allocation_size(val.change_percent) +
        FfiConverterOptionalInt64::allocation_size(val.trade_volume) +
        FfiConverterOptionalDouble::allocation_size(val.trade_value) +
        FfiConverterOptionalInt64::allocation_size(val.last_updated);
    
}


